import React, { useState, useEffect, useRef } from 'react';
import { ChatMessage } from '../types';
import { getGeminiResponse } from '../services/geminiService';

interface ChatSectionProps {
  onStartQuiz: () => void;
}

const ChatSection: React.FC<ChatSectionProps> = ({ onStartQuiz }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'model', text: "Akwaaba! I am Amoako. Do you want to know how AI makes your life easier in Ghana? Just ask me anything!" }
  ]);
  const [inputValue, setInputValue] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isTyping]);

  const handleSend = async () => {
    if (!inputValue.trim()) return;

    const userMsg: ChatMessage = { role: 'user', text: inputValue };
    setMessages(prev => [...prev, userMsg]);
    setInputValue('');
    setIsTyping(true);

    const aiResponse = await getGeminiResponse([...messages, userMsg]);
    setIsTyping(false);
    setMessages(prev => [...prev, { role: 'model', text: aiResponse }]);
  };

  return (
    <div className="w-full flex flex-col h-[75vh] bg-white rounded-3xl border-4 border-yellow-400 overflow-hidden shadow-2xl">
      {/* Chat Area */}
      <div 
        ref={scrollRef}
        className="flex-1 overflow-y-auto p-4 space-y-4 bg-[url('https://www.transparenttextures.com/patterns/cubes.png')] bg-opacity-5"
      >
        {messages.map((msg, idx) => (
          <div 
            key={idx} 
            className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-2`}
          >
            <div className={`max-w-[85%] p-4 rounded-2xl shadow-sm border-2 ${
              msg.role === 'user' 
                ? 'bg-yellow-400 border-yellow-500 text-black rounded-tr-none' 
                : 'bg-green-50 border-green-200 text-gray-800 rounded-tl-none'
            }`}>
              <p className="text-sm md:text-base leading-relaxed">{msg.text}</p>
            </div>
          </div>
        ))}
        {isTyping && (
          <div className="flex justify-start">
            <div className="bg-gray-100 p-4 rounded-2xl border-2 border-gray-200 rounded-tl-none">
              <span className="flex gap-1">
                <span className="w-2 h-2 bg-gray-400 rounded-full animate-bounce"></span>
                <span className="w-2 h-2 bg-gray-400 rounded-full animate-bounce [animation-delay:0.2s]"></span>
                <span className="w-2 h-2 bg-gray-400 rounded-full animate-bounce [animation-delay:0.4s]"></span>
              </span>
            </div>
          </div>
