          {["Tell me about WhatsApp AI", "AI in football", "AI in Ghana farms"].map((chip) => (
            <button
              key={chip}
              onClick={() => { setInputValue(chip); }}
              className="whitespace-nowrap bg-white border-2 border-green-200 text-green-700 px-3 py-1 rounded-full text-xs font-bold hover:bg-green-50 transition-colors"
            >
              {chip}
            </button>
