        </div>
      )}

      {/* Footer / Input */}
      <div className="p-4 bg-white border-t-4 border-yellow-400">
        <div className="flex gap-2">
          <input
            type="text"
            value={inputValue}
            onChange={(e) => setInputValue(e.target.value)}
            onKeyPress={(e) => e.key === 'Enter' && handleSend()}
            placeholder="Ask Amoako about AI..."
            className="flex-1 bg-gray-50 border-2 border-gray-200 rounded-xl px-4 py-3 focus:outline-none focus:border-green-500 transition-colors"
          />
          <button 
            onClick={handleSend}
            disabled={!inputValue.trim() || isTyping}
            className="bg-red-500 text-white p-3 rounded-xl border-b-4 border-red-700 active:border-b-0 active:translate-y-1 transition-all disabled:opacity-50"
