const QuizSection: React.FC<QuizSectionProps> = ({ onComplete }) => {
  const [loading, setLoading] = useState(true);
  const [quizState, setQuizState] = useState<QuizState>({
    questions: [],
    currentQuestionIndex: 0,
    score: 0,
    selectedAnswers: [],
    isFinished: false
  });
  const [feedback, setFeedback] = useState<{ isCorrect: boolean; message: string } | null>(null);

  useEffect(() => {
    const initQuiz = async () => {
      const q = await generateQuizQuestions();
      setQuizState(prev => ({ ...prev, questions: q }));
      setLoading(false);
    };
    initQuiz();
  }, []);

  const handleAnswerSelection = (answer: string) => {
    if (feedback) return;

    const currentQ = quizState.questions[quizState.currentQuestionIndex];
    const isCorrect = answer === currentQ.correctAnswer;

    setFeedback({
      isCorrect,
      message: isCorrect ? "Super! You got it right! 🎉" : `Almost! The correct answer was: ${currentQ.correctAnswer}`
    });

    setQuizState(prev => ({
      ...prev,
      score: isCorrect ? prev.score + 1 : prev.score,
      selectedAnswers: [...prev.selectedAnswers, answer]
    }));
  };

  const nextQuestion = () => {
    setFeedback(null);
    if (quizState.currentQuestionIndex === quizState.questions.length - 1) {
      setQuizState(prev => ({ ...prev, isFinished: true }));
    } else {
      setQuizState(prev => ({ ...prev, currentQuestionIndex: prev.currentQuestionIndex + 1 }));
    }
  };

  if (loading) {
    return (
      <div className="flex flex-col items-center justify-center space-y-4 p-12">
        <div className="w-16 h-16 border-8 border-orange-200 border-t-orange-500 rounded-full animate-spin"></div>
        <p className="font-heading font-bold text-gray-600">Generating your Challenge...</p>
      </div>
    );
  }

  if (quizState.isFinished) {
    const passed = quizState.score >= 2;
    return (
      <div className="w-full text-center space-y-6 bg-white p-8 rounded-3xl border-4 border-orange-400 shadow-2xl animate-in zoom-in">
        <div className="text-6xl">{passed ? "🏆" : "💪"}</div>
        <h2 className="text-3xl font-heading font-bold">
          {passed ? "Excellent Job, Star!" : "Keep Trying, Champ!"}
        </h2>
        <div className="text-6xl font-black text-green-600">
          {quizState.score} / {quizState.questions.length}
        </div>
        <p className="text-gray-600 px-4">
          {passed 
            ? "You really understand how AI works in our country! Go out and see if you can spot more AI around you." 
            : "AI is a big topic! Ask Amoako more questions to learn more secrets about how computers work."}
        </p>
        <button 
          onClick={onComplete}
          className="w-full py-4 bg-red-500 text-white font-bold text-xl rounded-2xl border-b-8 border-red-700 active:border-b-0 active:translate-y-2 transition-all shadow-lg"
        >
          Finish Challenge
        </button>
      </div>
    );
  }

  const currentQuestion = quizState.questions[quizState.currentQuestionIndex];

  return (
    <div className="w-full space-y-6 bg-white p-6 md:p-8 rounded-3xl border-4 border-orange-400 shadow-2xl relative">
      {/* Progress Bar */}
      <div className="flex justify-between items-center mb-4">
        <span className="text-sm font-bold text-gray-400">Question {quizState.currentQuestionIndex + 1} of 3</span>
        <div className="flex gap-1">
          {[0, 1, 2].map(i => (
            <div key={i} className={`w-8 h-2 rounded-full ${i <= quizState.currentQuestionIndex ? 'bg-green-500' : 'bg-gray-100'}`}></div>
          ))}
        </div>
      </div>

      <h3 className="text-2xl font-heading font-bold text-gray-800 leading-snug">
        {currentQuestion.question}
      </h3>

      <div className="space-y-3">
        {currentQuestion.options.map((opt, idx) => (
          <button
            key={idx}
            disabled={!!feedback}
            onClick={() => handleAnswerSelection(opt)}
            className={`w-full text-left p-4 rounded-xl border-2 font-medium transition-all transform hover:scale-[1.02] active:scale-95 ${
              feedback 
                ? opt === currentQuestion.correctAnswer 
                  ? 'bg-green-100 border-green-500 text-green-800 ring-4 ring-green-100' 
                  : quizState.selectedAnswers[quizState.currentQuestionIndex] === opt 
                    ? 'bg-red-100 border-red-500 text-red-800' 
                    : 'bg-gray-50 border-gray-100 text-gray-400'
                : 'bg-white border-orange-200 hover:border-orange-500 hover:bg-orange-50 text-gray-700'
            }`}
          >
            <span className="inline-block w-8 font-bold text-orange-500">{String.fromCharCode(65 + idx)}.</span> {opt}
          </button>
        ))}
      </div>

      {feedback && (
        <div className={`p-4 rounded-2xl animate-in slide-in-from-top-4 ${feedback.isCorrect ? 'bg-green-50 text-green-800' : 'bg-red-50 text-red-800'}`}>
          <p className="font-bold text-lg mb-1">{feedback.message}</p>
          <p className="text-sm opacity-90">{currentQuestion.explanation}</p>
          <button 
            onClick={nextQuestion}
            className="w-full mt-4 py-3 bg-gray-800 text-white font-bold rounded-xl border-b-4 border-black active:border-b-0 active:translate-y-1 transition-all"
          >
            {quizState.currentQuestionIndex === 2 ? "See Final Score" : "Next Question →"}
          </button>
        </div>
      )}
    </div>
  );
};

export default QuizSection;

