import { GoogleGenAI, Type } from "@google/genai";
import { ChatMessage, QuizQuestion } from "../types";

const MODEL_NAME = 'gemini-3-flash-preview';

export const getGeminiResponse = async (history: ChatMessage[]) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const systemInstruction = `
    You are 'Vera', a friendly AI tutor for Ghanaian students aged 11-14. 
    Explain Artificial Intelligence using simple English and local examples.
    Relatable examples: 
    - WhatsApp: How it predicts the next word you want to type.
    - TikTok/YouTube: How it knows which videos you like.
    - Google Maps: How it knows there is traffic on the Spintex Road or in Kumasi Central.
    - Farming: How a camera can tell if a cocoa leaf is sick.
    - Football: How video games make players move like real-world stars.

    Avoid jargon. If you must use a big word, explain it simply. 
    Keep responses short (under 100 words). Be encouraging and use 'Akwaaba' or 'Charlie' occasionally to build rapport.
  `;

  const contents = history.map(msg => ({
    role: msg.role === 'user' ? 'user' : 'model',
    parts: [{ text: msg.text }]
  }));

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: contents as any,
      config: {
        systemInstruction,
        temperature: 0.7,
      }
    });
    return response.text || "I'm sorry, I couldn't think of an answer. Can you ask again?";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Oh no, my internet is acting like a trotro in traffic! Please try again.";
  }
};

export const generateQuizQuestions = async (): Promise<QuizQuestion[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const prompt = "Generate 3 simple multiple-choice questions about AI for Ghanaian kids aged 11-14. Use local examples in the questions. Ensure the output is valid JSON.";

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              id: { type: Type.INTEGER },
              question: { type: Type.STRING },
              options: { 
                type: Type.ARRAY, 
                items: { type: Type.STRING } 
              },
              correctAnswer: { type: Type.STRING },
              explanation: { type: Type.STRING }
            },
            required: ["id", "question", "options", "correctAnswer", "explanation"]
          }
        }
      }
    });

    const jsonStr = response.text || "[]";
    return JSON.parse(jsonStr);
  } catch (error) {
    console.error("Quiz Generation Error:", error);
    // Fallback static questions if API fails
    return [
      {
        id: 1,
        question: "What is AI?",
        options: ["A robot that eats food", "A computer that learns to do smart things", "A magic box"],
        correctAnswer: "A computer that learns to do smart things",
        explanation: "AI helps computers solve problems like humans do!"
      },
      {
        id: 2,
        question: "Which of these uses AI?",
        options: ["A stone", "A simple pencil", "WhatsApp suggesting your next word"],
        correctAnswer: "WhatsApp suggesting your next word",
        explanation: "WhatsApp learns how you type to help you chat faster!"
      },
      {
        id: 3,
        question: "How can AI help a farmer in Ghana?",
        options: ["By planting the seeds by hand", "By detecting sick crops from photos", "By making it rain every day"],
        correctAnswer: "By detecting sick crops from photos",
        explanation: "AI can look at pictures of leaves and tell if they need medicine!"
      }
    ];
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { ChatMessage } from '../types';
import { getGeminiResponse } from '../services/geminiService';

interface ChatSectionProps {
  onStartQuiz: () => void;
}

const ChatSection: React.FC<ChatSectionProps> = ({ onStartQuiz }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'model', text: "Akwaaba! I am Vera. Do you want to know how AI makes your life easier in Ghana? Just ask me anything!" }
  ]);
  const [inputValue, setInputValue] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isTyping]);

  const handleSend = async () => {
    if (!inputValue.trim()) return;

    const userMsg: ChatMessage = { role: 'user', text: inputValue };
    setMessages(prev => [...prev, userMsg]);
    setInputValue('');
    setIsTyping(true);

    const aiResponse = await getGeminiResponse([...messages, userMsg]);
    setIsTyping(false);
    setMessages(prev => [...prev, { role: 'model', text: aiResponse }]);
  };

  return (
    <div className="chat-window animate-fade">
      <div ref={scrollRef} className="chat-messages">
        {messages.map((msg, idx) => (
          <div key={idx} className={`chat-bubble ${msg.role === 'user' ? 'user' : 'ai'}`}>
            <p>{msg.text}</p>
          </div>
        ))}
        {isTyping && (
          <div className="chat-bubble ai" style={{display: 'flex', gap: '4px'}}>
             <span style={{width: '6px', height: '6px', background: '#9ca3af', borderRadius: '50%'}}></span>
             <span style={{width: '6px', height: '6px', background: '#9ca3af', borderRadius: '50%'}}></span>
             <span style={{width: '6px', height: '6px', background: '#9ca3af', borderRadius: '50%'}}></span>
          </div>
        )}
      </div>

      <div className="chat-input-area">
        <div className="input-group">
          <input
            type="text"
            value={inputValue}
            onChange={(e) => setInputValue(e.target.value)}
            onKeyPress={(e) => e.key === 'Enter' && handleSend()}
            placeholder="Ask Vera about AI..."
            className="text-input"
          />
          <button onClick={handleSend} disabled={!inputValue.trim() || isTyping} className="btn-send">
            <svg style={{width: '24px', height: '24px'}} fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" />
            </svg>
          </button>
        </div>

        {messages.length >= 3 && (
          <button 
            onClick={onStartQuiz}
            style={{
              width: '100%', marginTop: '0.75rem', padding: '0.5rem',
              background: 'var(--color-green-600)', color: 'white',
              border: 'none', borderBottom: '4px solid var(--color-green-800)',
              borderRadius: '0.75rem', fontWeight: 'bold', cursor: 'pointer'
            }}
          >
            I'm Ready for the Quiz! 🎓
          </button>
        )}
      </div>
    </div>
  );
};

export default ChatSection;

import React, { useState, useEffect } from 'react';
import { QuizQuestion, QuizState } from '../types';
import { generateQuizQuestions } from '../services/geminiService';

interface QuizSectionProps {
  onComplete: () => void;
}

const QuizSection: React.FC<QuizSectionProps> = ({ onComplete }) => {
  const [loading, setLoading] = useState(true);
  const [quizState, setQuizState] = useState<QuizState>({
    questions: [],
    currentQuestionIndex: 0,
    score: 0,
    selectedAnswers: [],
    isFinished: false
  });
  const [feedback, setFeedback] = useState<{ isCorrect: boolean; message: string } | null>(null);

  useEffect(() => {
    const initQuiz = async () => {
      const q = await generateQuizQuestions();
      setQuizState(prev => ({ ...prev, questions: q }));
      setLoading(false);
    };
    initQuiz();
  }, []);

  const handleAnswerSelection = (answer: string) => {
    if (feedback) return;
    const currentQ = quizState.questions[quizState.currentQuestionIndex];
    const isCorrect = answer === currentQ.correctAnswer;
    setFeedback({
      isCorrect,
      message: isCorrect ? "Super! You got it right! 🎉" : `Almost! The correct answer was: ${currentQ.correctAnswer}`
    });
    setQuizState(prev => ({
      ...prev,
      score: isCorrect ? prev.score + 1 : prev.score,
      selectedAnswers: [...prev.selectedAnswers, answer]
    }));
  };

  const nextQuestion = () => {
    setFeedback(null);
    if (quizState.currentQuestionIndex === quizState.questions.length - 1) {
      setQuizState(prev => ({ ...prev, isFinished: true }));
    } else {
      setQuizState(prev => ({ ...prev, currentQuestionIndex: prev.currentQuestionIndex + 1 }));
    }
  };

  if (loading) {
    return (
      <div style={{display: 'flex', flexDirection: 'column', alignItems: 'center', padding: '3rem', gap: '1rem'}}>
        <div style={{width: '4rem', height: '4rem', border: '8px solid var(--color-orange-200)', borderTopColor: 'var(--color-orange-500)', borderRadius: '50%', animation: 'spin 1s linear infinite'}}></div>
        <p style={{fontWeight: 'bold', color: '#4b5563'}}>Generating your Challenge...</p>
        <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
      </div>
    );
  }

  if (quizState.isFinished) {
    const passed = quizState.score >= 2;
    return (
      <div className="card animate-fade">
        <div style={{fontSize: '4rem', marginBottom: '1.5rem'}}>{passed ? "🏆" : "💪"}</div>
        <h2 style={{fontSize: '2rem', marginBottom: '1rem'}}>{passed ? "Excellent Job, Star!" : "Keep Trying, Champ!"}</h2>
        <div style={{fontSize: '4rem', fontWeight: '900', color: 'var(--color-green-600)', marginBottom: '1.5rem'}}>
          {quizState.score} / {quizState.questions.length}
        </div>
        <p style={{color: '#4b5563', marginBottom: '1.5rem', padding: '0 1rem'}}>
          {passed 
            ? "You really understand how AI works in our country! Go out and see if you can spot more AI around you." 
            : "AI is a big topic! Ask Vera more questions to learn more secrets about how computers work."}
        </p>
        <button onClick={onComplete} className="btn-primary" style={{background: 'var(--color-red-500)', borderBottomColor: 'var(--color-red-700)'}}>
          Finish Challenge
        </button>
      </div>
    );
  }

  const currentQ = quizState.questions[quizState.currentQuestionIndex];

  return (
    <div className="card animate-fade" style={{textAlign: 'left'}}>
      <div style={{display: 'flex', justifyContent: 'space-between', marginBottom: '1.5rem'}}>
        <span style={{fontSize: '0.875rem', fontWeight: 'bold', color: '#9ca3af'}}>Question {quizState.currentQuestionIndex + 1} of 3</span>
      </div>

      <h3 style={{fontSize: '1.5rem', marginBottom: '1.5rem', lineHeight: '1.3'}}>{currentQ.question}</h3>

      <div style={{display: 'flex', flexDirection: 'column', gap: '0.75rem'}}>
        {currentQ.options.map((opt, i) => (
          <button
            key={i}
            onClick={() => handleAnswerSelection(opt)}
            disabled={!!feedback}
            style={{
              padding: '1rem', borderRadius: '0.75rem', textAlign: 'left', border: '2px solid',
              borderColor: feedback ? (opt === currentQ.correctAnswer ? 'var(--color-green-600)' : 'var(--color-gray-100)') : 'var(--color-orange-200)',
              background: feedback ? (opt === currentQ.correctAnswer ? 'var(--color-green-50)' : 'white') : 'white',
              cursor: feedback ? 'default' : 'pointer'
            }}
          >
            <b>{String.fromCharCode(65 + i)}.</b> {opt}
          </button>
        ))}
      </div>

      {feedback && (
        <div style={{marginTop: '1.5rem', padding: '1rem', borderRadius: '1rem', background: feedback.isCorrect ? 'var(--color-green-50)' : 'var(--color-red-50)'}}>
          <p style={{fontWeight: 'bold', marginBottom: '0.25rem'}}>{feedback.message}</p>
          <p style={{fontSize: '0.875rem', opacity: 0.8, marginBottom: '1rem'}}>{currentQ.explanation}</p>
          <button onClick={nextQuestion} style={{width: '100%', padding: '0.75rem', borderRadius: '0.75rem', background: '#1f2937', color: 'white', fontWeight: 'bold', border: 'none', cursor: 'pointer'}}>
            {quizState.currentQuestionIndex === 2 ? "Result" : "Next →"}
          </button>
        </div>
      )}
    </div>
  );
};

export default QuizSection;
